const html = event.Records[0].cf.response.body;
let body = html;
if (event.Records && event.Records[0] && event.Records[0].cf) {
    const headers = event.Records[0].cf.request.headers;

    if(headers['x-personalization']){
        const personalization = JSON.parse(Buffer.from(headers['x-personalization'][0].value, 'base64').toString('ascii'));
        body = injectContent(body, personalization);
    }
}
return {
    status: "200",
    headers: {
        "content-type": [{
            key: "Content-Type",
            value: "text/html"
        }]
    },
    body: body
};

function injectContent(html, personalization){

    const parser = new DOMParser();
    let doc = parser.parseFromString(html,'text/html');
    const head = doc.getElementsByTagName('head')[0];
    const body = doc.getElementsByTagName('body')[0];

    // Inject CSS
    const style = document.createElement("style");
    style.type = 'text/css';
    style.innerHTML = personalization['css'];
    head.appendChild(style);

    // Inject JS
    const script = document.createElement("script");
    script.type = 'text/javascript';
    script.innerHTML = personalization['js'];
    body.appendChild(script);

    return doc.documentElement.outerHTML;
}

